                'slug'             => 'bingo-caller-script',
                'category'         => 'hosting',
                'reading_time'     => '5 min read',
                'meta_description' => 'A complete bingo caller script with phrases, energy-building lines, and between-round announcements. Sound confident and professional at your next bingo event.',
